async (params, browser) => {
  // Open Airtable dashboard
  await browser.open('https://airtable.com')

  // Wait for bases to load
  await browser.waitForSelector('.baseContainer, [data-testid="base-card"], .base-card', 15000)

  // Let dashboard fully render
  await browser.wait(3000)

  // Extract base names, icons, and URLs
  const result = await browser.evaluate(`const bases = []; const cards = document.querySelectorAll('[data-testid="base-card"], .baseContainer, .base-card'); for (let i = 0; i < Math.min(cards.length, 50); i++) { const card = cards[i]; const nameEl = card.querySelector('[data-testid="base-name"], .baseCardName, .base-name, h3, span'); const name = nameEl?.textContent?.trim() || card.textContent?.trim()?.substring(0, 60) || ''; const link = card.closest('a') || card.querySelector('a'); const url = link?.href || ''; const iconEl = card.querySelector('.baseIcon, [data-testid="base-icon"], svg, img'); const icon = iconEl?.getAttribute('aria-label') || iconEl?.getAttribute('alt') || ''; if (name && name.length > 0) { bases.push({ name: name.substring(0, 100), url: url, icon: icon }); } } return { result_count: bases.length, bases: bases }`)

  return result
}
